// Build reverse map: offense -> category
const OFFENSE_TO_CAT = {};
Object.entries(CRIME_CATEGORIES).forEach(([cat, offenses]) => {
  offenses.forEach(o => { OFFENSE_TO_CAT[o] = cat; });
});

const ALL_CATEGORIES = Object.keys(CRIME_CATEGORIES);

// Color scale — consistent across all charts
const catColorScale = d3.scaleOrdinal()
  .domain(ALL_CATEGORIES)
  .range(['#4878d0','#60bd68','#f47a60','#7c7cc0','#b87333','#e05cdb','#ffa500','#6baed6','#c1440e']);

function getCatColor(cat) { return catColorScale(cat) || '#888'; }

// =============================================
// DATA — filter geo data to only real crimes
// =============================================
const CRIME_GEO = DATA.geo.filter(d => OFFENSE_TO_CAT[d.OFFENSE_DESCRIPTION]);

// Annotate geo data with category
CRIME_GEO.forEach(d => { d.CRIME_CAT = OFFENSE_TO_CAT[d.OFFENSE_DESCRIPTION]; });

// Build district-level aggregates from geo data
function buildDistrictAggregates() {
  const agg = {}; // {district: {cat: count}}
  CRIME_GEO.forEach(d => {
    if (!agg[d.DISTRICT]) agg[d.DISTRICT] = {};
    if (!agg[d.DISTRICT][d.CRIME_CAT]) agg[d.DISTRICT][d.CRIME_CAT] = 0;
    agg[d.DISTRICT][d.CRIME_CAT]++;
  });
  return agg;
}

// Build street-level aggregates from geo data
function buildStreetAggregates() {
  const agg = {};
  CRIME_GEO.forEach(d => {
    const street = d.STREET.split('\n')[0].trim();
    if (!agg[street]) agg[street] = {};
    if (!agg[street][d.CRIME_CAT]) agg[street][d.CRIME_CAT] = 0;
    agg[street][d.CRIME_CAT]++;
  });
  return agg;
}

const districtAgg = buildDistrictAggregates();
const streetAgg = buildStreetAggregates();

const tooltip = d3.select('#tooltip');
const dayOrder = ['Monday','Tuesday','Wednesday','Thursday','Friday','Saturday','Sunday'];

// =============================================
// VIZ 1: HEATMAP — Altair/Vega-Lite (time-based)
// Uses only actual crimes — recompute from geo data
// =============================================
(function() {
  // Recompute heatmap from filtered crime geo data
  const heatAgg = {};
  CRIME_GEO.forEach(d => {
    const key = d.DAY_OF_WEEK + '_' + d.HOUR;
    heatAgg[key] = (heatAgg[key] || 0) + 1;
  });
  const heatData = [];
  dayOrder.forEach(day => {
    for (let h = 1; h <= 23; h++) {
      const k = day + '_' + h;
      heatData.push({ DAY_OF_WEEK: day, HOUR: h, crime_count: heatAgg[k] || 0 });
    }
  });

  const spec = {
    "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
    "title": "Boston Crime Frequency by Day of Week and Hour (Actual Offenses Only)",
    "width": 600, "height": 250,
    "data": {"values": heatData},
    "mark": {"type": "rect", "tooltip": true},
    "encoding": {
      "x": {"field": "HOUR", "type": "ordinal", "title": "Hour of Day"},
      "y": {"field": "DAY_OF_WEEK", "type": "nominal", "title": "Day of Week", "sort": dayOrder},
      "color": {
        "field": "crime_count", "type": "quantitative", "title": "Number of Crimes",
        "scale": {"scheme": "blues"}
      },
      "tooltip": [
        {"field": "DAY_OF_WEEK", "type": "nominal", "title": "Day"},
        {"field": "HOUR", "type": "ordinal", "title": "Hour"},
        {"field": "crime_count", "type": "quantitative", "title": "Crime Count"}
      ]
    }
  };
  vegaEmbed('#viz-heatmap', spec, {actions: false});
})();

// =============================================
// VIZ 2: MONTHLY TREND with brush + crime type breakdown
// =============================================
(function() {
  const margin = {top:20, right:20, bottom:55, left:60};
  const width = 700 - margin.left - margin.right;
  const height = 280 - margin.top - margin.bottom;

  const svg = d3.select('#viz-monthly').append('svg')
    .attr('viewBox', `0 0 ${width+margin.left+margin.right} ${height+margin.top+margin.bottom}`)
    .append('g').attr('transform', `translate(${margin.left},${margin.top})`);

  const data = DATA.monthly;
  const x = d3.scaleBand().domain(data.map(d=>d.MONTH_STR)).range([0,width]).padding(0.05);
  const y = d3.scaleLinear().domain([0, d3.max(data,d=>d.count)*1.1]).nice().range([height,0]);

  const area = d3.area()
    .x(d=>x(d.MONTH_STR)+x.bandwidth()/2)
    .y0(height).y1(d=>y(d.count)).curve(d3.curveMonotoneX);
  const line = d3.line()
    .x(d=>x(d.MONTH_STR)+x.bandwidth()/2)
    .y(d=>y(d.count)).curve(d3.curveMonotoneX);

  svg.append('path').datum(data).attr('d',area).attr('fill','rgba(42,157,143,0.15)');
  svg.append('path').datum(data).attr('d',line).attr('fill','none').attr('stroke','#2a9d8f').attr('stroke-width',2.5);

  svg.selectAll('.dot').data(data).enter().append('circle')
    .attr('cx', d=>x(d.MONTH_STR)+x.bandwidth()/2).attr('cy', d=>y(d.count))
    .attr('r',5).attr('fill','#2a9d8f').attr('stroke','#fff').attr('stroke-width',2)
    .on('mouseover', function(e,d) {
      d3.select(this).attr('r',7);
      tooltip.style('opacity',1).html('<strong>'+d.MONTH_STR+'</strong><br>'+d.count+' incidents (all)<br><em style="font-size:0.9em">Actual crimes subset shown in brush view</em>');
    })
    .on('mousemove', function(e) { tooltip.style('left',(e.pageX+12)+'px').style('top',(e.pageY-30)+'px'); })
    .on('mouseout', function() { d3.select(this).attr('r',5); tooltip.style('opacity',0); });

  svg.append('g').attr('class','axis').attr('transform',`translate(0,${height})`)
    .call(d3.axisBottom(x)).selectAll('text').attr('transform','rotate(-40)').attr('text-anchor','end').style('font-size','10px');
  svg.append('g').attr('class','axis').call(d3.axisLeft(y).ticks(5));
  svg.append('text').attr('x',width/2).attr('y',height+50).attr('text-anchor','middle').style('font-size','12px').style('fill','#415a77').text('Month');
  svg.append('text').attr('transform','rotate(-90)').attr('x',-height/2).attr('y',-45).attr('text-anchor','middle').style('font-size','12px').style('fill','#415a77').text('Number of Incidents');

  // Brush
  const brush = d3.brushX().extent([[0,0],[width,height]])
    .on('end', function(event) {
      const summaryEl = d3.select('#monthly-summary');
      const typeChartEl = d3.select('#monthly-type-chart');
      if (!event.selection) { summaryEl.text(''); typeChartEl.html(''); return; }
      const [x0s,x1s] = event.selection;
      const selected = data.filter(d => {
        const cx = x(d.MONTH_STR)+x.bandwidth()/2;
        return cx >= x0s && cx <= x1s;
      });
      if (!selected.length) return;
      const total = d3.sum(selected, d=>d.count);
      const avg = Math.round(total/selected.length);
      summaryEl.html('<strong>Selected '+selected.length+' month(s)</strong> ('+selected[0].MONTH_STR+' → '+selected[selected.length-1].MONTH_STR+'): '+total+' total incidents, ~'+avg+' avg/month.');

      // Build crime type breakdown for selected months from geo data
      // Parse month from geo date (OCCURRED_ON_DATE not available, use rough count)
      // Use geo data filtered by approximate time — show category breakdown of all crime geo
      const catCounts = {};
      ALL_CATEGORIES.forEach(c => catCounts[c] = 0);
      CRIME_GEO.forEach(d => { if (catCounts[d.CRIME_CAT] !== undefined) catCounts[d.CRIME_CAT]++; });

      const catData = ALL_CATEGORIES.map(c => ({cat: c, count: catCounts[c]}))
        .filter(d => d.count > 0)
        .sort((a,b) => b.count - a.count);

      // Draw horizontal bar chart
      typeChartEl.html('');
      const bm = {top:10, right:20, bottom:20, left:170}, bw=460-bm.left-bm.right, bh=30*catData.length;
      const bsvg = typeChartEl.append('svg')
        .attr('viewBox',`0 0 ${bw+bm.left+bm.right} ${bh+bm.top+bm.bottom}`)
        .append('g').attr('transform',`translate(${bm.left},${bm.top})`);

      const bx = d3.scaleLinear().domain([0,d3.max(catData,d=>d.count)]).range([0,bw]);
      const by = d3.scaleBand().domain(catData.map(d=>d.cat)).range([0,bh]).padding(0.2);

      bsvg.selectAll('rect').data(catData).enter().append('rect')
        .attr('x',0).attr('y',d=>by(d.cat)).attr('width',d=>bx(d.count)).attr('height',by.bandwidth())
        .attr('fill',d=>getCatColor(d.cat)).attr('rx',3);

      bsvg.selectAll('.val').data(catData).enter().append('text')
        .attr('x',d=>bx(d.count)+4).attr('y',d=>by(d.cat)+by.bandwidth()/2+4)
        .style('font-size','11px').style('fill','#415a77').text(d=>d.count);

      bsvg.append('g').call(d3.axisLeft(by)).select('.domain').remove();
      bsvg.selectAll('.tick text').style('font-size','11px').style('fill','#2c3e50');

      summaryEl.html(summaryEl.html() + ' <em style="font-size:0.9em;color:#778da9">Crime type breakdown below reflects full dataset distribution.</em>');
    });
  svg.append('g').call(brush);
  svg.append('text').attr('x',width/2).attr('y',-5).attr('text-anchor','middle').style('font-size','11px').style('fill','#778da9').text('← Click and drag to select a time range');
})();

// =============================================
// VIZ 3: GEO MAP — Leaflet with real Boston street map
// =============================================
let showShootingsOnly = false;
let selectedGeoDistrict = 'All';
let selectedGeoCat = 'All';
let leafletMap, markerLayer;

(function() {
  // Populate district dropdown
  const distSelect = d3.select('#geo-district');
  DATA.allDistricts.forEach(d => distSelect.append('option').attr('value',d).text(d));
  distSelect.on('change', function() { selectedGeoDistrict = this.value; updateLeafletMarkers(); });

  // Populate crime category dropdown
  const catSelect = d3.select('#geo-crime-cat');
  ALL_CATEGORIES.forEach(c => catSelect.append('option').attr('value',c).text(c));
  catSelect.on('change', function() { selectedGeoCat = this.value; updateLeafletMarkers(); });

  // Initialize Leaflet map centered on Boston
  leafletMap = L.map('viz-geomap').setView([42.325, -71.085], 12);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
    maxZoom: 18
  }).addTo(leafletMap);

  markerLayer = L.layerGroup().addTo(leafletMap);

  // Build legend
  const legendEl = d3.select('#geo-legend');
  ALL_CATEGORIES.forEach(cat => {
    const item = legendEl.append('div').attr('class','geo-legend-item');
    item.append('div').attr('class','geo-legend-swatch').style('background', getCatColor(cat));
    item.append('span').text(cat);
  });

  updateLeafletMarkers();
})();

function updateLeafletMarkers() {
  markerLayer.clearLayers();
  let filtered = CRIME_GEO;
  if (selectedGeoDistrict !== 'All') filtered = filtered.filter(d=>d.DISTRICT===selectedGeoDistrict);
  if (selectedGeoCat !== 'All') filtered = filtered.filter(d=>d.CRIME_CAT===selectedGeoCat);
  if (showShootingsOnly) filtered = filtered.filter(d=>d.SHOOTING===1);

  // Limit to 2000 for performance
  const sample = filtered.length > 2000 ? filtered.filter((_,i)=>i%Math.ceil(filtered.length/2000)===0) : filtered;

  sample.forEach(d => {
    if (!d.Lat || !d.Long || d.Lat < 42.2 || d.Lat > 42.42) return;
    const color = showShootingsOnly ? '#c1440e' : getCatColor(d.CRIME_CAT);
    const marker = L.circleMarker([d.Lat, d.Long], {
      radius: showShootingsOnly ? 7 : 5,
      fillColor: color,
      color: showShootingsOnly ? '#fff' : 'rgba(255,255,255,0.5)',
      weight: showShootingsOnly ? 2 : 0.5,
      fillOpacity: 0.75
    });
    marker.bindPopup(
      '<strong>'+d.OFFENSE_DESCRIPTION+'</strong><br>'+
      'Category: <span style="color:'+color+'">'+d.CRIME_CAT+'</span><br>'+
      'District: '+d.DISTRICT+'<br>Street: '+d.STREET.split('\n')[0]+
      '<br>'+d.DAY_OF_WEEK+' at '+d.HOUR+':00'+
      (d.SHOOTING ? '<br><span style="color:#c1440e">⚠ Shooting involved</span>' : '')
    );
    markerLayer.addLayer(marker);
  });
}

function toggleShooting() {
  showShootingsOnly = !showShootingsOnly;
  d3.select('#geo-shooting').classed('active', showShootingsOnly)
    .text(showShootingsOnly ? 'Show All Crimes' : 'Show Shootings Only');
  updateLeafletMarkers();
}

// =============================================
// VIZ 4: DISTRICT INTERACTIVE BAR — D3
// =============================================
(function() {
  const ctrlEl = d3.select('#district-type-controls');
  const vizEl = d3.select('#viz-districts');

  const types = ['Total', ...ALL_CATEGORIES];
  let activeType = 'Total';

  // Build dropdown
  ctrlEl.append('label').style('font-weight','600').style('font-size','0.9em').style('color','#415a77').text('Crime Category:');
  const distSelect = ctrlEl.append('select')
    .style('margin-left','10px').style('padding','6px 14px').style('border','1px solid #ccc')
    .style('border-radius','6px').style('font-family','inherit').style('font-size','0.9em')
    .style('background','#fff').style('cursor','pointer')
    .on('change', function() { activeType = this.value; drawDistrictChart(); });
  types.forEach(t => distSelect.append('option').attr('value',t).text(t));

  function drawDistrictChart() {
    vizEl.html('');

    // Compute data
    let chartData;
    if (activeType === 'Total') {
      chartData = Object.entries(districtAgg).map(([dist, cats]) => ({
        district: dist,
        count: Object.values(cats).reduce((a,b)=>a+b, 0)
      }));
    } else {
      chartData = Object.entries(districtAgg).map(([dist, cats]) => ({
        district: dist,
        count: cats[activeType] || 0
      }));
    }
    chartData = chartData.filter(d=>d.count>0).sort((a,b)=>b.count-a.count).slice(0,10);

    const margin = {top:20, right:20, bottom:40, left:60};
    const width = 620 - margin.left - margin.right;
    const height = 280 - margin.top - margin.bottom;

    const svg = vizEl.append('svg')
      .attr('viewBox',`0 0 ${width+margin.left+margin.right} ${height+margin.top+margin.bottom}`)
      .append('g').attr('transform',`translate(${margin.left},${margin.top})`);

    const x = d3.scaleBand().domain(chartData.map(d=>d.district)).range([0,width]).padding(0.25);
    const y = d3.scaleLinear().domain([0,d3.max(chartData,d=>d.count)*1.1]).nice().range([height,0]);
    const color = activeType === 'Total' ? '#415a77' : getCatColor(activeType);

    svg.selectAll('rect').data(chartData).enter().append('rect')
      .attr('x',d=>x(d.district)).attr('y',d=>y(d.count))
      .attr('width',x.bandwidth()).attr('height',d=>height-y(d.count))
      .attr('fill',color).attr('rx',3)
      .on('mouseover',function(e,d){
        d3.select(this).attr('opacity',0.8);
        tooltip.style('opacity',1).html('<strong>'+d.district+'</strong><br>'+activeType+': '+d.count);
      })
      .on('mousemove',function(e){tooltip.style('left',(e.pageX+12)+'px').style('top',(e.pageY-30)+'px');})
      .on('mouseout',function(){d3.select(this).attr('opacity',1);tooltip.style('opacity',0);});

    svg.selectAll('.val').data(chartData).enter().append('text')
      .attr('x',d=>x(d.district)+x.bandwidth()/2).attr('y',d=>y(d.count)-5)
      .attr('text-anchor','middle').style('font-size','11px').style('fill','#2c3e50').text(d=>d.count);

    svg.append('g').attr('class','axis').attr('transform',`translate(0,${height})`).call(d3.axisBottom(x));
    svg.append('g').attr('class','axis').call(d3.axisLeft(y).ticks(5));
    svg.append('text').attr('x',width/2).attr('y',height+35).attr('text-anchor','middle').style('font-size','12px').style('fill','#415a77').text('District');
    svg.append('text').attr('transform','rotate(-90)').attr('x',-height/2).attr('y',-45).attr('text-anchor','middle').style('font-size','12px').style('fill','#415a77').text('Crime Count');
  }
  drawDistrictChart();
})();

